    private Map<String, DataHandler> getAttachmentMap(SIMSMultipartRequest mreq, String apname) {
        Map<String, DataHandler> map = new LinkedHashMap<>();
        try {
            Collection attachments = mreq.getFile("at");
            for (Object o : attachments) {
                UploadedFile uf = (UploadedFile) o;
                map.put(uf.getFilesystemName(), new DataHandler(new FileDataSource(uf.getFile())));
            }
        } catch (Exception e) {
            System.out.println("Get attachment files for mass email failed: " + e.getMessage());
            e.printStackTrace();
        }
        return map;
    }

