    //privilege check
    SIMSMultipartRequest mreq = (SIMSMultipartRequest) request.getAttribute("massActionMultipartRequest");
    String apname = mreq.getParameter("a");
    String path = mreq.getParameter("p");
    String formName = URLDecoder.decode(mreq.getParameter("fn"), "UTF-8");
    User user = (User) session.getAttribute("USER");

    if(!UserFeatureAccessModule.ifAllow(session,apname,Const.FUNC_MASS_EMAIL)) return;

    IPChecker ipChecker=new IPChecker(request.getRemoteAddr());
    boolean spamIP="AF".equalsIgnoreCase(ipChecker.getContinentCode());

    
    //get the reply-to, subject, content
    String reply = user.getUserId();
    String personal = user.getUserName(apname, true);
    if (personal == null || personal.isEmpty()) personal = null;
    String subject = mreq.getParameter("s");
    String content = mreq.getParameter("c");
    String domainId = mreq.getParameter("d");
    boolean realSend = Encoder.parseBoolean(mreq.getParameter("real"), false);
    if (reply == null || reply.isEmpty() || subject == null || subject.isEmpty() ||
            content == null || content.isEmpty()) return;
    if(realSend && (domainId == null || domainId.isEmpty())) return;
//  RagicConfig rc = RagicConfig.getInstance();
//  String sender_email = rc.hasProperty("SMTP_SENDER_EMAIL")?rc.getProperty("SMTP_SENDER_EMAIL"): Const.MAIL_SENDER_ID;

    boolean ifGhosted=SystemData.getInstance().getProperty("GHOSTED_"+apname)!=null || session.getAttribute("GHOSTED")!=null;
    boolean ifContentScreen=false;
    if(subject.toLowerCase().contains("urgent") && content.toLowerCase().contains("http")){
        if(ifContentScreen){
            SystemData.getInstance().setProperty("GHOSTED_"+apname, "Suspiciouc email content "+ Encoder.formatAsStandardDate(new Date(),true));
            ifGhosted=true;
        }
        new Mail2().compose("jeff@ragic.com",null,"support@ragic.com","Email Watchdog","Suspicous Email blocked:"+apname,
                "Suspicous Email: "+subject+" - "+content).send();
    }

    //for real send
    DES des = new DES();
    AccountPaymentStatus aps = Account.getInstance(apname).getPaymentStatus(true);
    out.println("<script>var magic=parent.document.getElementById('magic');</script>");
    int count = 0, invalid = 0;
    if (realSend) {
        //get the emailList
        int emailDomainId = -1;
        try {
            emailDomainId = Integer.parseInt(domainId);
        } catch (Exception ignored) {
        }
        if (emailDomainId == -1) return;

        BDBWorker worker = new BDBWorker(apname);
        try {
            //get the unregistered list
            Set<String> unreglist = new HashSet<>();
            SDBQuery u = new SDBQueryFull(worker);
            SDBNode node;
            u.go(DConst.NOTIFY_UNREGISTERED);
            while ((node = u.next()) != null) {
                unreglist.add(node.getValue());
            }

            //get the email
            NUIFormSet set = NUIFormSetInfo.loadBrowsingFormSet(session, apname, path, formName);
            NUIForm form = set.getForm();
            if (form.getType() != NUIForm.NUI_TABLE) return;
            APIQuery query = new APIQuery(set.getApname(), set.getPath(), set.getSheetIndex());
            query.setUpdateMode();
            List<NUIFilter> filterList = set.getCurrentFilter();
            for (NUIFilter filter : filterList) {
                query.addFilter(filter.getDomainId(), filter);
            }
            APIResultsFull arPrecheck=query.getAPIResultsFull();
            int preCheckCount=0;
            for(APIEntry e:arPrecheck){
                if(e==null) continue;
                preCheckCount++;
            }

            if(preCheckCount>1000){
                Date trialStartDate=Account.getInstance(apname).getPaymentStatus().getTrialStartDate();
                if(trialStartDate==null) trialStartDate=new Date(0L);
                long trialSince=new Date().getTime() - trialStartDate.getTime();
                if(trialSince<48L*Const.HOUR_MILLI){
                    ifGhosted=true;
                    SystemData.getInstance().setProperty("GHOSTED_"+apname, "Automatic "+ Encoder.formatAsStandardDate(new Date(),true));
                    new Mail2().compose("jeff@ragic.com",null,"support@ragic.com","Email Watchdog","Auto ghosted account:"+apname,
                            "Sending mass email in "+(trialSince/Const.HOUR_MILLI)+" hours of getTrialStartDate.").send();
                }
            }

            APIResultsFull ar=query.getAPIResultsFull();
            for(APIEntry e:ar){
                if(e==null) continue;
                if(count>10000) break;
                String email = e.getFieldValue(emailDomainId);
                System.out.println("Sending:" + email);

                //validate if is an e-mail address
                if (email == null || email.length() < 5) {
                    invalid++;
                    continue;
                }
                if (!Encoder.ifEmailValid(email)) {
                    invalid++;
                    continue;
                }

                //check if unregistered
                if(ifGhosted){
                    //notify the progress
                    out.println("<script>magic.value=\"$('mmailstatus').innerHTML='Mailing <b>" + email + "</b>';\";magic.click();</script>");
                    response.flushBuffer();
                    out.flush();

                    Thread.sleep(10000);
                    count++;
                }
                else if (unreglist.contains(email)) {
                    //skip, notify the progress
                    out.println("<script>magic.value=\"$('mmailstatus').innerHTML='Skipping <b>" + email + "</b>';\";magic.click();</script>");
                    response.flushBuffer();
                    out.flush();
                    invalid++;
                }
                //ok to send
                else {
                    //notify the progress
                    out.println("<script>magic.value=\"$('mmailstatus').innerHTML='Mailing <b>" + email + "</b>';\";magic.click();</script>");
                    response.flushBuffer();
                    out.flush();

                    //sending the e-mail
                    String replyForEmailHistory = License.isDistr() ? user.getUserId() : com.ragic.s3.nui.helper.Util.getReplyEmailForEmailHistory(apname, path, Integer.parseInt(form.getSheetIndex()), e.getRootNodeId());

                    CustomEmailTemplateHandler handler = CustomEmailTemplateHandlerFactory.getInstance(Const.CUSTOM_EM_TYPE_SIMPLE);
                    handler.addParam("ap", apname);
                    handler.addParam("path", path);
                    handler.addParam("sheetIndex", Integer.parseInt(form.getSheetIndex()));
                    handler.addParam("userName", personal);
                    handler.addParam("userEmail", user.getUserId());
                    handler.addParam("nodeId", e.getRootNodeId());
                    String replacedContent = handler.processCustomEmailTemplateTags(content, CustomEmailTemplateProcessMode.PLAIN_TEXT, null); // TODO: change to html mode after mass-email supports custom html template
                    String replacedSubject = handler.processCustomEmailTemplateTags(subject, CustomEmailTemplateProcessMode.PLAIN_TEXT, null);

                    if(!QuotaManager.getInstance().ifBanMassEmail(form.getApname()) && !spamIP){//temporaty ban for sending spam
                        Mail2 mail2 = new Mail2();
                        //currently Amazon SES does not support our replyForEmailHistory e-mail addresses
                        mail2.setMassServer();
                        mail2.setApname(apname);
                        mail2.compose(email, null, replyForEmailHistory, personal, replacedSubject, Encoder.textToHTML(replacedContent, false));
                        mail2.setTagLine("<br><br><br><br>--<br>Sent via <a href='https://www.ragic.com'>Ragic</a><br>Data management that actually works<br><br><br><a style='color:#ccc;' href='" + Util.getServerUrl() + "/sims/mmailer/unreg.jsp?u2=" + URLEncoder.encode(des.encrypt(apname + "|" + email), "UTF-8") + "&act=unsubscribe" + "'>Unsubscribe</a>");

                        Map<String, DataHandler> attMap = this.getAttachmentMap(mreq, apname);
                        mail2.setAttachmentMap(attMap);
                        mail2.send();

                        List<String> attList = new ArrayList<>(attMap.keySet());
                        try {
                            EmailHistory eh = com.ragic.s3.nui.helper.Util.createEmailHistory(reply, email, null, subject, replacedContent, attList);
                            eh.save(apname, path, Integer.parseInt(form.getSheetIndex()), e.getRootNodeId());
                        } catch (Exception e_history) {
                            e_history.printStackTrace();
                        }
                    }

                    Thread.sleep(2000);
                    count++;
                }
            }

            //notify
            if(count>100){
                new Mail2().compose("jeff@ragic.com",null,"support@ragic.com","Email Watchdog",apname+" send "+count+" messages"+(ifGhosted?" ghosted":""),
                        "<a href='https://www.ragic.com/"+apname+"'>"+apname+"</a>"+
                                "Count:"+count+"<br>"+
                                "Subject:"+subject+"<br>"+
                                "Content:"+content
                ).send();
            }

        } catch (Exception e) {
            out.println(e.getMessage());
            e.printStackTrace();
        } finally {
            worker.commit();
        }
    }

    //test sending
    else {
        //notify the progress
        out.println("<script>magic.value=\"$('mmailstatus').innerHTML='Mailing <b>" + user.getUserId() + "</b>';\";magic.click();</script>");
        response.flushBuffer();
        out.flush();

        NUIFormSet set = NUIFormSetInfo.loadBrowsingFormSet(session, apname, path, formName);
        NUIForm form = set.getForm();
        //Test sending the e-mail
        Mail2 mail2 = new Mail2();
        mail2.setMassServer();
        CustomEmailTemplateHandler handler = CustomEmailTemplateHandlerFactory.getInstance(Const.CUSTOM_EM_TYPE_SIMPLE);
        handler.addParam("ap", apname);
        handler.addParam("path", path);
        handler.addParam("sheetIndex", Integer.parseInt(form.getSheetIndex()));
        handler.addParam("userName", personal);
        handler.addParam("nodeId", -1);
        String replacedContent = handler.processCustomEmailTemplateTags(content, CustomEmailTemplateProcessMode.PLAIN_TEXT, null); // TODO: change to html mode after mass-email supports custom html template
        String replacedSubject = handler.processCustomEmailTemplateTags(subject, CustomEmailTemplateProcessMode.PLAIN_TEXT, null);

        mail2.setApname(apname);
        mail2.compose(user.getUserId(), null, reply, personal, replacedSubject, Encoder.textToHTML(replacedContent, false));
        mail2.setTagLine("<br><br><br><br>--<br>Sent via <a href='https://www.ragic.com'>Ragic</a><br><br><br><a style='color:#ccc;' href='" + Util.getServerUrl() + "/sims/mmailer/unreg.jsp?u2=" + URLEncoder.encode(des.encrypt(apname + "|" + user.getUserId()), "UTF-8") + "&act=unsubscribe" + "'>Unsubscribe</a>");
        mail2.send();
        count++;
    }

    //update credit
    //aps.addEmailBalance(count*-1);//smart worker problem
    //BDBSmartWorker bs=new BDBSmartWorker(Const.AP_RAGIC);
    //int bal=0;
    //try{bal=Integer.parseInt(bs.getFieldValue(DConst.ROOT_APNAME,apname,DConst.ROOT_BALANCE_EMAIL));}catch(Exception e){}
    //bs.setFieldValue(DConst.ROOT_APNAME,apname,DConst.ROOT_BALANCE_EMAIL,""+(bal+(count*-1)));

    //int currentBalance=aps.getEmailBalance();
    //Account.getInstance(apname).updateLicenseStatus();

    //notify the progress
    out.println("<script>magic.value=\"$('mmailstatus').innerHTML=" +
            "'All done! Mailed <b>" + count + "</b> recipient. (" + invalid + " invalid addreses)';\";magic.click();</script>");
    response.flushBuffer();
    out.flush();

